const buildItemTypeSearchWhereClause = (query = '') => {
  const searchTerms = getItemTypeSearchTerms(query);
  const baseWhereClause = {
    item_type_status: 'ACTIVE'
  };

  if (!searchTerms.length) {
    return baseWhereClause;
  }

  return {
    ...baseWhereClause,
    [Op.or]: searchTerms.flatMap((term) => ([
      { item_type_name: { [Op.iLike]: `%${term}%` } },
      { item_type_description: { [Op.iLike]: `%${term}%` } }
    ]))
  };
};

const parseDivisionCodes = (value) => {
  if (value === undefined || value === null || value === '') {
    return [];
  }

  const rawValues = Array.isArray(value) ? value : String(value).split(',');
  return rawValues
    .map((item) => Number(item))
    .filter((item) => Number.isFinite(item));
};

