ItemLibrary.getLicensorsWithProperties = async (req, result) => {
  try {
    const divisionCodes = parseDivisionCodes(req.query?.divisionCode ?? req.body?.divisionCode);
    const propertyWhereClause = {
      is_active: true,
      mgTypeCode: PROPERTY_MERCH_GROUP_TYPE,
    };

    if (divisionCodes.length) {
      propertyWhereClause.divisionCode_id_fk = {
        [Op.in]: divisionCodes,
      };
    }

    const properties = await sql.merchGroup.findAll({
      attributes: ['mg_id', 'mg_code', 'mg_desc', 'divisionCode_id_fk', 'parent_id', 'mgCode2', 'mgCategory'],
      where: propertyWhereClause,
      order: [['mg_desc', 'ASC']],
      raw: true,
    });

    const licensorIds = [...new Set(
      properties
        .map((property) => property.parent_id)
        .filter((parentId) => parentId !== null && parentId !== undefined)
    )];

    if (!licensorIds.length) {
      return result(null, []);
    }

    const licensors = await sql.merchGroup.findAll({
      attributes: ['mg_id', 'mg_code', 'mg_desc', 'divisionCode_id_fk', 'parent_id', 'mgCode2', 'mgCategory'],
      where: {
        mg_id: {
          [Op.in]: licensorIds,
        },
        mgTypeCode: LICENSOR_MERCH_GROUP_TYPE,
      },
      order: [['mg_desc', 'ASC']],
      raw: true,
    });

    const propertiesByLicensorId = new Map();

    properties.forEach((property) => {
      if (property.parent_id === null || property.parent_id === undefined) {
        return;
      }

      const licensorProperties = propertiesByLicensorId.get(property.parent_id) || [];
      licensorProperties.push(mapMerchGroupOption(property));
      propertiesByLicensorId.set(property.parent_id, licensorProperties);
    });

    const licensorsWithProperties = licensors
      .map((licensor) => ({
        ...mapMerchGroupOption(licensor),
        properties: propertiesByLicensorId.get(licensor.mg_id) || [],
      }))
      .filter((licensor) => licensor.properties.length);

    result(null, licensorsWithProperties);
  } catch (err) {
    console.error('Error in getLicensorsWithProperties:', err);
    result(err, null);
  }
};

ItemLibrary.getAllitems = async (req, result) => {
  const { startRow, endRow, filterModel } = req.query;
