    const itemTypeImgThumbnail = String(req.body.item_type_img_thumbnail || '').trim();
    const itemTypeImgFullsize = String(req.body.item_type_img_fullsize || '').trim();

    if (!itemTypeName || !itemTypeDescription || !itemTypeImgThumbnail || !itemTypeImgFullsize) {
      return result(null, { statusCode: 400, message: 'Missing required fields.' });
    }

    const existingItemType = await sql.itemType.findOne({
      where: Sequelize.where(
        Sequelize.fn('lower', Sequelize.col('item_type_name')),
        itemTypeName.toLowerCase()
      )
    });

    if (existingItemType) {
      return result(null, { statusCode: 409, message: 'Item type already exists.' });
    }

    const createdItemType = await sql.itemType.create({
      item_type_name: itemTypeName,
      item_type_description: itemTypeDescription,
      item_type_img_thumbnail: itemTypeImgThumbnail,
      item_type_img_fullsize: itemTypeImgFullsize,
      item_type_status: 'ACTIVE',
      created_user_fk: userInfo?.name,
      created_time_date: new Date()
    });

    result(null, { statusCode: 200, data: createdItemType });
  } catch (err) {
    result(null, err);
  }
};

function buildItemNumberCandidate(mappedItemHeader, attemptIndex) {
  const date = new Date();
  const suffix = attemptIndex === 0
    ? parseInt(date.getSeconds()) + 1
    : Math.floor(Math.random() * 90 + 10);

  return [
    "LIB-",
    mappedItemHeader.udf_merchgroup01 ?? "",
    mappedItemHeader.udf_merchgroup02 ?? "",
    mappedItemHeader.udf_merchgroup03 ?? "",
    mappedItemHeader.udf_merchgroup04 ?? "",
    date.getDay().toString(),
    '-',
    suffix,
    '-',
    mappedItemHeader.udf_merchgroup05_fk ?? "",
  ].join('');
}

async function itemNumberExists(styleNumber) {
  const [itemHeader, rfqItem] = await Promise.all([
    sql.itemHeader.findOne({
      where: {
        item_num_id: styleNumber
      }
    }),
    sql.RFQItem.findOne({
      where: {
        rfqItem_style_number: styleNumber
      }
    })
  ]);

  return Boolean(itemHeader?.dataValues || itemHeader || rfqItem?.dataValues || rfqItem);
}

async function generateUniqueItemNumber(mappedItemHeader) {
  for (let attemptIndex = 0; attemptIndex < ITEM_NUMBER_GENERATION_MAX_ATTEMPTS; attemptIndex++) {
    const candidate = buildItemNumberCandidate(mappedItemHeader, attemptIndex);
    if (!await itemNumberExists(candidate)) {
      return candidate;
    }
  }

  return null;
}

ItemLibrary.getItemByNumber = async (req, result) => {
  itemNumber = req.params.itemNumber
  if (!itemNumber || itemNumber.length < 3) {
    return result(null, []); // Skip if input is too short
  }

  try {
    const items = await sql.itemHeader.findAll({
      attributes: ['item_id_pk', 'item_num_id'],
      where: {
        [Op.and]: [
          {
            item_num_id: {
              [Op.iLike]: `${itemNumber}%` // Case-insensitive partial match
            }
          },
          {
            item_active_status: {
              [Op.eq]: 'Y' // Only active items
            }
          },
          {
            is_item_old: {
              [Op.is]: false // Only new items
            }
          }
        ]
      },
      order: [
        ['item_num_id', 'ASC'], // Sort alphabetically
        ['created_time_date', 'DESC'] // Newest first
      ],
      limit: 10 // Limit suggestions
    });

    result(null, items || []); // Return raw results
  } catch (err) {
    console.error('Error in getItemByNumber:', err);
    result(err, null);
  }
};

ItemLibrary.getItemsByDsnRefNum = async (dsnRefNum, result) => {
  await sql.itemHeader.findAll({
    where: {
      dsn_ref_num: dsnRefNum
    },
    include: [{
      model: sql.itemAttachment,
      as: 'itemAttachments',
      order: [Sequelize.literal('item_num_id_fk'), Sequelize.literal('attachment_display_name')]
    }]
  })
  .then(async (data) => {
    if (data) {
      result(null, data);
    } else {
      result(null, null);
    }
  })
  .catch(err => {
    result(err, null);
  });
};

module.exports = ItemLibrary;

