export interface RfqImportFieldGap {
  field: string;
  reason: string;
  source: 'missing-from-item-library' | 'missing-on-selected-item' | 'requires-rfq-context';
}

export interface ItemLibraryToRfqDefaults {
  rfqGroup?: unknown;
  customer?: unknown;
  deliveryLocation?: unknown;
  status?: unknown;
  step?: unknown;
  quantity?: unknown;
  casePack?: unknown;
  techPackLink?: unknown;
}

export type ItemLibraryRow = Record<string, unknown>;
export type RfqDraftRow = Record<string, unknown>;

const EMPTY_VALUES = new Set(['', 'null', 'undefined', 'n/a', 'na']);

export const RFQ_FIELDS_NOT_SUPPLIED_BY_ITEM_LIBRARY: RfqImportFieldGap[] = [
  {
    field: 'RFQ Group',
    reason: 'RFQ-only grouping/work queue; Item Library has no RFQ campaign/group context.',
    source: 'requires-rfq-context',
  },
  {
    field: 'Customer',
    reason: 'RFQ quote customer drives dilution/logistics and selling context; Item Library vendor/customer fields are product-master fields.',
    source: 'requires-rfq-context',
  },
  {
    field: 'Delivery Location',
    reason: 'RFQ landed-cost context; Item Library does not store the quote delivery destination.',
    source: 'requires-rfq-context',
  },
  {
    field: 'Quantity',
    reason: 'RFQ quote quantity; Item Library stores the product, not the buy quantity for a quote round.',
    source: 'missing-from-item-library',
  },
  {
    field: 'Case Pack',
    reason: 'RFQ costing/launch prerequisite; Item Library list rows do not provide RFQ case-pack data.',
    source: 'missing-from-item-library',
  },
  {
    field: 'Tech Pack Link',
    reason: 'RFQ launch prerequisite; Item Library image/attachments are not the RFQ tech-pack link.',
    source: 'missing-from-item-library',
  },
  {
    field: 'Status',
    reason: 'RFQ workflow status should be chosen/defaulted for the new RFQ row.',
    source: 'requires-rfq-context',
  },
  {
    field: 'Step',
    reason: 'RFQ workflow step should be chosen/defaulted for the new RFQ row.',
    source: 'requires-rfq-context',
  },
  {
    field: 'Factory/Vendor Quotes',
    reason: 'RFQ detail rows need factories, quote prices, quote status, notes, and quote dates; Item Library has no RFQVendor rows.',
    source: 'missing-from-item-library',
  },
  {
    field: 'Costing Inputs',
    reason: 'FOB cost, freight, duty, CBM/pc, container, warehouse, and margin/price-for-sales fields are RFQ costing data, not Item Library product-master data.',
    source: 'missing-from-item-library',
  },
];

function hasValue(value: unknown): boolean {
  if (value == null) {
    return false;
  }
  if (Array.isArray(value)) {
    return value.length > 0;
  }
  if (typeof value === 'object') {
    return Object.keys(value as Record<string, unknown>).length > 0;
  }
  return !EMPTY_VALUES.has(String(value).trim().toLowerCase());
}

function firstValue(row: ItemLibraryRow, keys: string[]): unknown {
  for (const key of keys) {
    if (hasValue(row[key])) {
      return row[key];
    }
  }
  return undefined;
}

function asRfqOption(title: unknown, id: unknown): unknown {
  if (!hasValue(title) && !hasValue(id)) {
    return undefined;
  }
  if (typeof title === 'object' && title !== null) {
    return title;
  }
  return {
    title,
    ...(hasValue(id) ? { id } : {}),
  };
}

function imageFromItemLibrary(row: ItemLibraryRow): unknown {
  const picture = firstValue(row, ['Picture', 'pic', 'image', 'Image']);
  if (picture && typeof picture === 'object') {
    return picture;
  }
  if (hasValue(picture)) {
    return {
      FullSizePicture: picture,
      Thumbnail: picture,
    };
  }
  return undefined;
}

export function buildRfqDraftFromItemLibrary(
  item: ItemLibraryRow,
  defaults: ItemLibraryToRfqDefaults = {}
): RfqDraftRow {
  const picture = imageFromItemLibrary(item);

  return {
    'Price Code': firstValue(item, ['itemNum', 'Item Num', 'item_num_id', 'refNum', 'Ref Num']),
    Description: firstValue(item, ['item_name', 'Item Name', 'Description', 'Product Name']),
    Picture: picture,
    FullSizePicture: picture && typeof picture === 'object'
      ? (picture as Record<string, unknown>).FullSizePicture
      : undefined,
    Material: asRfqOption(
      firstValue(item, ['Product Type ( Material)', 'material', 'Material']),
      firstValue(item, ['material_id', 'Product Type ( Material)_id', 'Material_id'])
    ),
    Construction: asRfqOption(
      firstValue(item, ['Product Sub-Type (Construction)', 'construction', 'Construction']),
      firstValue(item, ['construction_id', 'Product Sub-Type (Construction)_id', 'Construction_id'])
    ),
    Treatment: asRfqOption(
      firstValue(item, ['Product Sub-Sub-Type (feature)', 'feature', 'Treatment']),
      firstValue(item, ['feature_id', 'Product Sub-Sub-Type (feature)_id', 'Treatment_id'])
    ),
    'Size (LxW)': asRfqOption(
      firstValue(item, ['size', 'Size', 'Size (LxW)']),
      firstValue(item, ['size_id', 'Size_id', 'Size (LxW)_id'])
    ),
    License: asRfqOption(
      firstValue(item, ['licensor', 'Licensor', 'property', 'Property']),
      firstValue(item, ['licensor_id', 'Licensor_id', 'property_id', 'Property_id'])
    ),
    'RFQ Group': defaults.rfqGroup,
    Customer: defaults.customer,
    'Delivery Location': defaults.deliveryLocation,
    Status: defaults.status,
    Step: defaults.step,
    Quantity: defaults.quantity,
    'Case Pack': defaults.casePack,
    'Tech Pack Link': defaults.techPackLink,
  };
}

export function getMissingRfqDataForItemLibraryImport(
  item: ItemLibraryRow,
  defaults: ItemLibraryToRfqDefaults = {}
): RfqImportFieldGap[] {
  const draft = buildRfqDraftFromItemLibrary(item, defaults);
  const selectedItemFields: Array<[string, string]> = [
    ['Price Code', 'Item Library item number/ref number is required to identify the RFQ row.'],
    ['Description', 'RFQ rows need a product description.'],
    ['Material', 'RFQ copy/launch validation depends on Product Type.'],
    ['Construction', 'RFQ copy/launch validation depends on Product Sub-Type.'],
    ['Treatment', 'RFQ copy/launch validation depends on Product Sub-Sub-Type.'],
  ];
  const selectedItemGaps = selectedItemFields
    .filter(([field]) => !hasValue(draft[field]))
    .map(([field, reason]) => ({
      field,
      reason,
      source: 'missing-on-selected-item' as const,
    }));

  const contextualFields: Array<[keyof ItemLibraryToRfqDefaults, string]> = [
    ['rfqGroup', 'RFQ Group'],
    ['customer', 'Customer'],
    ['deliveryLocation', 'Delivery Location'],
    ['status', 'Status'],
    ['step', 'Step'],
    ['quantity', 'Quantity'],
    ['casePack', 'Case Pack'],
    ['techPackLink', 'Tech Pack Link'],
  ];
  const contextGaps = contextualFields
    .filter(([key]) => !hasValue(defaults[key]))
    .map(([, field]) => RFQ_FIELDS_NOT_SUPPLIED_BY_ITEM_LIBRARY.find((gap) => gap.field === field))
    .filter((gap): gap is RfqImportFieldGap => Boolean(gap));

  return [
    ...selectedItemGaps,
    ...contextGaps,
    ...RFQ_FIELDS_NOT_SUPPLIED_BY_ITEM_LIBRARY.filter((gap) => (
      gap.field === 'Factory/Vendor Quotes' || gap.field === 'Costing Inputs'
    )),
  ];
}

