import { Injectable } from '@angular/core'
import { Observable, pipe } from 'rxjs'
import { HttpClient, HttpParams } from '@angular/common/http'
import { map, catchError } from 'rxjs/operators';
import { HttpHeaders } from '@angular/common/http';
import { environment } from '../../../environments/environment';
import { CommentInterface } from 'src/app/pages/comments/types/commentInterface';

export type ProductAssignmentRole =
  | 'creative_designer'
  | 'creative_director'
  | 'technical_designer'
  | 'licensing_person'
  | 'salesperson';

export interface ProductAssignmentUser {
  id: number;
  name: string;
  lastname: string;
  email: string;
  profile_photo?: string | null;
  level?: string;
}

export interface ProductAssignment {
  id: number;
  item_id_fk: number;
  role: ProductAssignmentRole;
  user_id_fk: number;
  user?: ProductAssignmentUser;
}

export interface ProductAssignmentUpdate {
  role: ProductAssignmentRole;
  userId?: number | null;
  user_id_fk?: number | null;
}

@Injectable()
export class ItemDetailService {
  serverAddress = environment.item_master + '/detail';
  private comments: CommentInterface[] = [];

  constructor(private http: HttpClient) { }

  setUserAuth() {
    let token = localStorage.getItem("token")
    const headers = new HttpHeaders().set('Authorization', token)
    return headers
  }

  setUserAuthWithLoader() {
    let token = localStorage.getItem("token")
    const headers = new HttpHeaders()
      .set('Authorization', token)
      .set('X-Enable-Loader', 'true')
    return headers
  }

  getItemInfo(id: any) {
    return this.http.post<any>(`${this.serverAddress}/getItemInfo`, id, { headers: this.setUserAuth() })
  }

  setPrimaryImage(item: object) {
    return this.http.post(`${this.serverAddress}/setPrimaryImage`, item)
  }
  
  addComment(comment: CommentInterface) {
    return this.http.post<any>(`${this.serverAddress}/addComment`, comment, { headers: this.setUserAuth() })
  }

  getComments(id: number) {
    return this.http.get<any>(`${this.serverAddress}/getComments/${id}`, { headers: this.setUserAuthWithLoader() })
  }

  updateComment(id: number, comment: string) {
    return this.http.post<any>(`${this.serverAddress}/updateComment/${id}`, { comment }, { headers: this.setUserAuth() })
  }

  updateData(data: any) {
    return this.http.post<any>(`${this.serverAddress}/updateData`, data, { headers: this.setUserAuth() })
  }

  getLicenseFeedBacks(data) {
    return this.http.post<any>(`${this.serverAddress}/getLicenseFeedBacks`, data, { headers: this.setUserAuth() })
  }

  AddLicensingStatus(data: any) {
    return this.http.post<any>(`${this.serverAddress}/AddLicensingStatus`, data, { headers: this.setUserAuth() })
  }

  BulkAddLicensingStatus(data: any) {
    return this.http.post<any>(`${this.serverAddress}/BulkAddLicensingStatus`, data, { headers: this.setUserAuth() })
  }
  
  DeleteLicensingStatus(data: any) {
    return this.http.post<any>(`${this.serverAddress}/DeleteLicensingStatus`, data, { headers: this.setUserAuth() })
  }

  GetLicensingStatus(id) {
    return this.http.get<any>(`${this.serverAddress}/GetLicensingStatus/${id}`, { headers: this.setUserAuth() })
  }

  UpdateLicensingStatus(data: { id: number, assignee_id: number | null }) {
    return this.http.post<any>(`${this.serverAddress}/UpdateLicensingStatus`, data, { headers: this.setUserAuth() })
  }

  BulkGetLicensingStatus(data) {
    return this.http.post<any>(`${this.serverAddress}/BulkGetLicensingStatus`, data, { headers: this.setUserAuth() })
  }

  reqStyeNumber(data: any) {
    return this.http.post<any>(`${this.serverAddress}/reqStyeNumber`, data, { headers: this.setUserAuth() })
  }

  updateItemHeader(data){
    return this.http.post<any>(`${this.serverAddress}/updateItemHeader`, data, { headers: this.setUserAuth() })
  }

  getNotifications() {
    return this.http.get<any[]>(`${this.serverAddress}/GetNotifications`, { headers: this.setUserAuth() })
  }

  GetLicensingTimeline(itemId: number): Observable<any> {
    return this.http.get<any>(`${this.serverAddress}/GetLicensingTimeline/${itemId}`, { headers: this.setUserAuth() });
  }

  GetLicensingFeedbackReplies(licensingStatusId: number) {
    return this.http.get<any>(`${this.serverAddress}/GetLicensingFeedbackReplies/${licensingStatusId}`, { headers: this.setUserAuth() });
  }

  AddLicensingFeedbackReply(payload: {
    licensing_status_id_fk: number;
    comment: string;
    tagged_user_ids: number[];
    attachments?: { name: string; link: string; type: string; size: number }[];
  }) {
    return this.http.post<any>(`${this.serverAddress}/AddLicensingFeedbackReply`, payload, { headers: this.setUserAuth() });
  }

  getProductAssignments(itemId: number): Observable<{ status: boolean; roles: ProductAssignmentRole[]; data: ProductAssignment[] }> {
    return this.http.get<{ status: boolean; roles: ProductAssignmentRole[]; data: ProductAssignment[] }>(
      `${this.serverAddress}/assignments/${itemId}`,
      { headers: this.setUserAuth() }
    );
  }

  setProductAssignments(
    itemId: number,
    assignments: ProductAssignmentUpdate[] | Partial<Record<ProductAssignmentRole, number | null>>
  ): Observable<{ status: boolean; roles: ProductAssignmentRole[]; data: ProductAssignment[] }> {
    return this.http.post<{ status: boolean; roles: ProductAssignmentRole[]; data: ProductAssignment[] }>(
      `${this.serverAddress}/assignments/${itemId}`,
      { assignments },
      { headers: this.setUserAuth() }
    );
  }

  clearProductAssignment(itemId: number, role: ProductAssignmentRole): Observable<{ status: boolean; deleted: number }> {
    return this.http.delete<{ status: boolean; deleted: number }>(
      `${this.serverAddress}/assignments/${itemId}/${role}`,
      { headers: this.setUserAuth() }
    );
  }
}

