  syncLicensorDisabledState(): void {
    if (this.isSpruceNonLicDivision() || !this.selectedDivisionCode || this.license.length === 0) {
      this.licenseControler.disable({ emitEvent: false });
    } else {
      this.licenseControler.enable({ emitEvent: false });
