  private syncLicensorValidators(): void {
    const licenseRequired =
      !this.licenseControler.disabled &&
      !this.isSpruceNonLicDivision() &&
      !!this.selectedDivisionCode &&
      this.license.length > 0;

    if (licenseRequired) {
      this.licenseControler.setValidators([Validators.required]);
    } else {
      this.licenseControler.clearValidators();
    }
    this.licenseControler.updateValueAndValidity({ emitEvent: false });
  }

