  private async loadMGCategories(): Promise<void> {
    try {
      this.allMgCategories = await this.adminService.getMerchGroupCategories().toPromise();
      this.filterCategoriesByDivision();
    } catch {
      this.allMgCategories = [];
      this.mgCategories = [];
    }
