  private filterCategoriesByDivision(): void {
    if (!this.selectedDivisionCode) {
      this.mgCategories = [];
      return;
    }

    const divId = this.selectedDivisionCode.divCode_id;

    if (divId === POP_LIC_DIV_CODE_ID) {
      const allowedPop = ['Wall', 'Tabletop', 'Clock'];
      this.mgCategories = this.allMgCategories.filter(cat =>
        allowedPop.some(allowed => cat.mgCategory && cat.mgCategory.toLowerCase().includes(allowed.toLowerCase()))
      );
    } else if (divId === SPRUCE_LIC_DIV_CODE_ID) {
      const allowedSpruceLic = ['Storage', 'Workspace', 'Floor', 'Garden'];
      this.mgCategories = this.allMgCategories.filter(cat =>
        allowedSpruceLic.some(allowed => cat.mgCategory && cat.mgCategory.toLowerCase().includes(allowed.toLowerCase()))
      );
    } else {
      this.mgCategories = [...this.allMgCategories];
    }

    if (this.selectedCategory && !this.mgCategories.find(c => c.id === this.selectedCategory.id)) {
      this.onCategoryChange(null);
    }
  }

  async onDivisionChange(division: any): Promise<void> {
    this.selectedDivisionCode = division;
    this.divisionControler.setValue(division);
    this.resetFormForDivisionChange();
    this.filterCategoriesByDivision();
    this.syncLicensorDisabledState();
    if (division) {
      this.categoryControler.enable();
      await this.getMerchGroups(division);
    } else {
      this.categoryControler.disable();
      this.clearMerchGroupData();
    }
    this.updateSaveButtonState();
  }

  onCategoryChange(category: any): void {
    this.selectedCategory = category;
    this.categoryControler.setValue(category);
    this.resetProductFields();
    if (category) {
      this.activeMaterialOptions = this.material
        .filter(option => option.mgCategory === category.mgCategory)
        .sort((a, b) => a.title.localeCompare(b.title));
      this.productTypeControler.enable();
    } else {
      this.activeMaterialOptions = [];
      this.productTypeControler.disable();
    }
    this.refreshProductTypeOptions();
    this.updateSaveButtonState();
  }

