  private getCustomerDetails() {
    const selected = this.customerControler.value;
    // The value seeded from a copied row only has { title, id } — no dilution/logistics_load.
    // Look up the full customer record from the loaded list to get the real values.
    const fullCustomer = this.customer.find(c =>
      (selected?.id && c.id === selected.id) ||
      (selected?.title && c.title === selected.title)
    );
    return {
      dilution: fullCustomer?.dilution ?? selected?.dilution ?? '',
      logistics_load: fullCustomer?.logistics_load ?? selected?.logistics_load ?? ''
    };
  }

