  async checkPriceCode(priceCode) {

    try {
      const res: any = await firstValueFrom(this.itemService.findRFQItemByPriceCode({ priceCode: priceCode }));
      if (res.status == true) {
        let oldPriceCodeArray = res.data.rfqItem_style_number.split('-');
        if (oldPriceCodeArray.length == 2) {
          this.priceCode[10] = `-A`;
        } else {
          const str = oldPriceCodeArray[oldPriceCodeArray.length - 1];
          const nextLetter = String.fromCharCode(str.charCodeAt(str.length - 1) + 1);
          this.priceCode[10] = `-${nextLetter.toUpperCase()}`;
        }
      }
    } catch (err) {
      console.error('[addNewProductComponent] findRFQItemByPriceCode failed:', err);
      this._snackBar.open('Could not check the next RFQ version code. Please try again. / 无法检查下一个 RFQ 版本编号，请重试。', 'Close', { duration: 5000 });
    }
  }
  addRoyality() {
    let licenceTextValue = ''
    for (var i = 0; this.selectedValues.length > i; i++) {
      if (i != this.selectedValues.length - 1) {
        licenceTextValue = this.selectedValues[i].title + "," + licenceTextValue
      } else {
        licenceTextValue = licenceTextValue + this.selectedValues[i].title
      }
    }
    // Guard: ensure License is an object before writing to it
    if (!this.newItem.License || typeof this.newItem.License !== 'object') {
      this.newItem.License = {};
    }
    this.newItem.License.title = licenceTextValue
    let highestRoyalty = 0;
    let fobHighestRoyalty = 0;
    for (var i = 0; i < this.selectedValues.length; i++) {
      const royaltyRate = this.selectedValues[i].royalty_rate ?? 0;
      const fobRoyaltyRate = this.selectedValues[i].fob_royalty_rate ?? 0;
      if (royaltyRate > highestRoyalty) {
        highestRoyalty = royaltyRate;
        fobHighestRoyalty = fobRoyaltyRate;
      }
    }
    this.newItem['Lic FOB Royalty %'] = fobHighestRoyalty
    this.newItem['Lic POE Royalty %'] = highestRoyalty
    this.newItem['Lic MDDP Royalty %'] = highestRoyalty
    this.newItem['Lic Whse Royalty %'] = highestRoyalty
    this.newItem['Gen FOB Royalty %'] = 0
    this.newItem['Gen POE Royalty %'] = 0
    this.newItem['Gen MDDP Royalty %'] = 0
    this.newItem['Gen Whse Royalty %'] = 0
    this.newItem['royalty'] = highestRoyalty
  }

  getLicenseString(data) {
    if (!data) return '';
    let licenceTextValue = "";
    if (data.title == null) {
      // Array of license objects
      if (!Array.isArray(data) || data.length === 0) return '';
      for (var i = 0; data.length > i; i++) {
        if (i != data.length - 1) {
          licenceTextValue = data[i].title + "," + licenceTextValue
        } else {
          licenceTextValue = licenceTextValue + data[i].title
        }
      }
      return licenceTextValue;
    } else {
      return data.title
    }
  }
  getDivisionString(data: any): string {
    if (!data) return '';
    if (Array.isArray(data)) {
      if (!data.length) return '';
      if (data[0]?.divCode_code != undefined) {
        return data.map((d: any) => d.divCode_code).filter(Boolean).join(',');
      }
    }
    if (data.divCode_code) return data.divCode_code;
    if (data.title != undefined) return data.title;
    return String(data);
  }

  async onPriceCodeChange(element, value) {
