        this.assignmentUsers = (users || []).slice().sort((a, b) =>
          this.getUserDisplayName(a).localeCompare(this.getUserDisplayName(b))
        );
        this.loadingProductAssignmentUsers = false;
      },
      error: (err) => {
        console.error('[ItemDetailComponent] getAllUsers failed:', err);
        this.assignmentUsers = [];
        this.loadingProductAssignmentUsers = false;
      }
    });
  }

  applyProductAssignmentsFromItem(assignments: any[]): void {
    const nextAssignments: Partial<Record<ProductAssignmentRole, ProductAssignmentUser | null>> = {};
    for (const { role } of this.productAssignmentRoles) {
      const assignment = assignments.find(a => a.role === role);
      nextAssignments[role] = assignment?.user || null;
    }
    this.selectedProductAssignments = nextAssignments;
  }

  getUserDisplayName(user: ProductAssignmentUser | null | undefined): string {
    if (!user) return '';
    return `${user.name || ''} ${user.lastname || ''}`.trim() || user.email || `User ${user.id}`;
  }

  compareAssignmentUsers = (
    left: ProductAssignmentUser | null,
    right: ProductAssignmentUser | null
  ): boolean => {
    return (left?.id ?? null) === (right?.id ?? null);
  };

  async onProductAssignmentChange(role: ProductAssignmentRole, event: MatSelectChange): Promise<void> {
    const selectedUser = event.value as ProductAssignmentUser | null;
    const payload: ProductAssignmentUpdate[] = [{
      role,
      userId: selectedUser?.id ?? null,
    }];

    this.savingProductAssignmentRole = role;
    try {
      const response = await firstValueFrom(
        this.ItemDetailService.setProductAssignments(this.itemDetailId, payload)
      );
      this.itemData[0].productUserAssignments = response.data;
      this.applyProductAssignmentsFromItem(response.data);
      this._snackBar.open('Product assignment updated.', 'close', { duration: 2000 });
    } catch (err) {
      console.error('[ItemDetailComponent] setProductAssignments failed:', err);
      this._snackBar.open('Could not update product assignment.', 'close', { duration: 3000 });
    } finally {
      this.savingProductAssignmentRole = null;
    }
  }

