  /** Open the factory bulk-upload dialog (vendor role only). */
  onFactoryBulkUpload() {
    // Resolve vendor display name from the decoded JWT stored in localStorage.
    let vendorName = '';
    try {
      const token = localStorage.getItem('token') || '';
      const payload = JSON.parse(atob(token.split('.')[1]));
      vendorName = payload?.name || '';
    } catch { /* ignore decode errors */ }

    const dialogRef = this.dialog.open(FactoryBulkUploadDialogComponent, {
      width: '600px',
      disableClose: false,
      data: { vendorName },
    });

    dialogRef.afterClosed().subscribe((result: { refresh: boolean } | null) => {
      if (result?.refresh) {
        // Reload the RFQ grid so the newly created items appear
        this.getAllRFQItem();
        this._snackBar.open('Offers imported successfully.', 'Close', { duration: 4000 });
      }
    });
  }

