  private notifyRfqItemStatusChanged(
    newStatus: { title?: string } | string | null | undefined,
    rowData?: Record<string, unknown> | null
  ): void {
    const rawTitle = typeof newStatus === 'string' ? newStatus : newStatus?.title;
    const title = rawTitle?.trim();
    if (!title) {
      return;
    }
    const normalized = title.toLowerCase();
    if (normalized !== 'active' && normalized !== 'inactive' && normalized !== 'draft') {
      return;
    }
    const priceCode =
      rowData?.['Price Code'] ??
      (this.getMasterFiledName('price_code') ? rowData?.[this.getMasterFiledName('price_code')] : undefined);
    const itemLabel =
      priceCode != null && String(priceCode).trim() ? ` for ${priceCode}` : '';
    this._snackBar.open(`RFQ status updated to ${title}${itemLabel}.`, 'Close', {
      duration: 5000,
      verticalPosition: 'bottom',
      horizontalPosition: 'center',
    });
  }

