  private async confirmStatusChangeAllowed(rowData: any, newStatus: any): Promise<boolean> {
    const blockingValidation = canChangeRfqStatusToActive(
      rowData,
      newStatus,
      this.getMasterFiledName('tech_pack_url'),
      this.getRfqStatusToActiveValidationContextWithoutTechPack()
    );
    if (!blockingValidation.allowed) {
      this._snackBar.open(blockingValidation.message, 'ok', { duration: 10000 });
      return false;
    }

    const rowsMissingTechPack = this.getDraftRowsNeedingTechPackWarning([rowData], newStatus);
    if (!rowsMissingTechPack.length) {
      return true;
    }

    return await this.confirmProceedWithoutTechPack(rowsMissingTechPack.length);
  }

  private getDraftRowsNeedingTechPackWarning(rows: any[], newStatus: any): any[] {
    if (!this.isActiveStatusValue(newStatus)) {
      return [];
    }
    return rows.filter((rowData) => {
      if (!this.isDraftStatusValue(rowData?.[this.getMasterFiledName('status')])) {
        return false;
      }
      const validation = canChangeRfqStatusToActive(
        rowData,
        newStatus,
        this.getMasterFiledName('tech_pack_url'),
        this.getTechPackOnlyValidationContext()
      );
      return !validation.allowed && validation.missingFields?.includes(RFQ_TECH_PACK_LINK_FIELD);
    });
  }

